@code {
    private List<Channel> channels = new();
    private List<Message> messages = new();
    private List<ThreadSummary> threadSummaries = new();
    private List<Message> threadReplies = new();

    private Channel? activeChannel;
    private int activeChannelId;
    private Message? threadRootMessage;
    private bool threadOpen;

    private string newMessageContent = string.Empty;
    private string threadReplyContent = string.Empty;

    private int? hoveredMessageId;
    private int? emojiPickerMessageId;
    private bool isLoadingMore;
    private int messageSkip;
    private const int PageSize = 30;

    private ElementReference messageListRef;
    private CancellationTokenSource cts = new();

    private static readonly string[] commonEmojis = { "👍", "❤️", "😂", "🎉", "🤔", "👀" };

    protected override async Task OnInitializedAsync()
    {
        channels = await ChatService.GetChannelsAsync();
    }

    private async Task SelectChannelAsync(Channel channel)
    {
        activeChannel = channel;
        activeChannelId = channel.Id;
        messageSkip = 0;
        messages.Clear();
        threadSummaries.Clear();
        CloseThread();

        messages = await ChatService.GetMessagesAsync(channel.Id, 0, PageSize);
        messageSkip = messages.Count;

        BuildThreadSummaries();

        await ChatService.MarkChannelReadAsync(channel.Id);

        // Refresh channel list to update unread counts
        channels = await ChatService.GetChannelsAsync();
    }

    private async Task OnScrollAsync()
    {
        // Scroll-to-top triggers loading older messages
        // In a real app, JS interop would detect scroll position
        // Here we provide a simplified trigger
    }

    public async Task LoadOlderMessagesAsync()
    {
        if (isLoadingMore || activeChannel is null) return;

        isLoadingMore = true;
        StateHasChanged();

        var older = await ChatService.GetMessagesAsync(activeChannelId, messageSkip, PageSize);
        if (older.Any())
        {
            messages.InsertRange(0, older);
            messageSkip += older.Count;
            BuildThreadSummaries();
        }

        isLoadingMore = false;
        StateHasChanged();
    }

    private async Task SendMessageAsync()
    {
        if (string.IsNullOrWhiteSpace(newMessageContent) || activeChannel is null) return;

        var sent = await ChatService.SendMessageAsync(activeChannelId, newMessageContent.Trim(), null);
        messages.Add(sent);
        messageSkip++;
        newMessageContent = string.Empty;
    }

    private async Task OpenThreadAsync(Message rootMessage)
    {
        threadRootMessage = rootMessage;
        threadOpen = true;
        emojiPickerMessageId = null;

        threadReplies = await ChatService.GetThreadAsync(rootMessage.Id);
    }

    private void CloseThread()
    {
        threadOpen = false;
        threadRootMessage = null;
        threadReplies.Clear();
        threadReplyContent = string.Empty;
    }

    private async Task SendThreadReplyAsync()
    {
        if (string.IsNullOrWhiteSpace(threadReplyContent) || threadRootMessage is null) return;

        var reply = await ChatService.SendMessageAsync(
            activeChannelId, threadReplyContent.Trim(), threadRootMessage.Id);
        threadReplies.Add(reply);
        threadReplyContent = string.Empty;

        BuildThreadSummaries();
    }

    private async Task AddReactionAsync(int messageId, string emoji)
    {
        await ChatService.AddReactionAsync(messageId, emoji);
        emojiPickerMessageId = null;

        // Refresh messages to show updated reactions
        if (activeChannel is not null)
        {
            messages = await ChatService.GetMessagesAsync(activeChannelId, 0, messageSkip);
        }

        if (threadRootMessage is not null)
        {
            threadReplies = await ChatService.GetThreadAsync(threadRootMessage.Id);
        }
    }

    private void ToggleEmojiPicker(int messageId)
    {
        emojiPickerMessageId = emojiPickerMessageId == messageId ? null : messageId;
    }

    private async Task OnMessageKeyDown(KeyboardEventArgs e)
    {
        if (e.Key == "Enter" && !e.ShiftKey)
        {
            await SendMessageAsync();
        }
    }

    private async Task OnThreadKeyDown(KeyboardEventArgs e)
    {
        if (e.Key == "Enter" && !e.ShiftKey)
        {
            await SendThreadReplyAsync();
        }
    }

    private void BuildThreadSummaries()
    {
        threadSummaries = messages
            .Where(m => m.ReplyToId is not null)
            .GroupBy(m => m.ReplyToId!.Value)
            .Select(g => new ThreadSummary(g.Key, g.Count(), g.Max(m => m.SentAt)))
            .ToList();
    }

    private static string FormatRelativeTime(DateTime sentAt)
    {
        var diff = DateTime.UtcNow - sentAt;

        if (diff.TotalMinutes < 1) return "just now";
        if (diff.TotalMinutes < 60) return $"{(int)diff.TotalMinutes} min ago";
        if (diff.TotalHours < 24) return $"{(int)diff.TotalHours}h ago";
        if (diff.TotalDays < 7) return $"{(int)diff.TotalDays}d ago";
        return sentAt.ToString("MMM d, yyyy");
    }

    private static string TruncateDescription(string description)
    {
        return description.Length > 40 ? description[..37] + "..." : description;
    }

    public void Dispose()
    {
        cts.Cancel();
        cts.Dispose();
    }
}

